// Build financial snapshot from Vitalis API response
const vitalisData = $('Vitalis: Fetch Team Time Log').first().json;
const scenario = $('Webhook: Sync Trigger').first().json.body?.scenario || 'base';
const entries = vitalisData.entries || [];
const teamSummary = vitalisData.team_summary || [];

// Default FX rate (EGP per USD)
const usdEgp = 50.0;
const egpToUsd = 1.0 / usdEgp;

// Aggregate entries by month
const monthly = {};
for (const entry of entries) {
  // Parse date to get year-month
  const date = new Date(entry.date);
  const year = date.getFullYear();
  const month = date.getMonth() + 1;
  const key = `${year}-${String(month).padStart(2, '0')}`;

  if (!monthly[key]) {
    monthly[key] = { month: key, total_hours: 0, by_member: [] };
  }
  const hours = parseFloat(entry.minutes || 0) / 60;
  monthly[key].total_hours += hours;
  monthly[key].by_member.push({
    name: entry.member_name || entry.name,
    hours: hours,
    date: entry.date,
    task: entry.task || entry.description || ''
  });
}

// Build team members list from summary
const team_members = teamSummary.map(m => ({
  name: m.name,
  email: m.email,
  total_hours: m.total_hours,
  total_minutes: m.total_minutes
}));

const snapshot = {
  generated_at: new Date().toISOString(),
  scenario: scenario,
  currency: { egp_to_usd: egpToUsd, usd_egp: usdEgp },
  vitalis_period: vitalisData.period,
  total_entries: vitalisData.count,
  total_hours: vitalisData.total_hours,
  team_costs: {
    monthly_summary: Object.values(monthly),
    team_members: team_members
  },
  assumptions: $('Webhook: Sync Trigger').first().json.body?.assumptions || {},
  customer_growth: $('Webhook: Sync Trigger').first().json.body?.customer_growth || {},
};

return [{ json: snapshot }];
